2. **进程调度 (scheduler)**:
```c
void scheduler(void) {
  struct cpu *c = mycpu();
  c->proc = 0;

  for(;;) {
    // 遍历进程表寻找可运行进程
    for(struct proc *p = proc; p < &proc[NPROC]; p++) {
      acquire(&p->lock);
      if(p->state == RUNNABLE) {
        // 切换到进程
        p->state = RUNNING;
        c->proc = p;
        swtch(&c->context, &p->context);
        c->proc = 0;
      }
      release(&p->lock);
    }
  }
}
```

